using Microsoft.AspNetCore.Mvc; using Valora.Application.Contracts; using Valora.Application.DTOs; using Valora.Application.Services;
namespace Valora.Api.Controllers; [ApiController] public sealed class SurveysController(ISurveyRepository surveys,AuditService audit):ControllerBase{ [HttpGet("/surveys/public/{token}")] public async Task<IActionResult> Public(string token){ var s=await surveys.GetPublicByTokenAsync(token); return s is null?NotFound():Ok(s);} [HttpPost("/surveys/{surveyId:guid}/responses")] public async Task<IActionResult> Submit(Guid surveyId,SubmitResponseRequest r){ var id=await surveys.SaveResponseAsync(surveyId,r); await audit.LogAsync(new(null,null,"survey.submit_response","response",id.ToString(),"Resposta recebida pela API.")); return Created($"/responses/{id}/result",new{id}); } [HttpGet("/responses/{responseId:guid}/result")] public async Task<IActionResult> Result(Guid responseId){ var result=await surveys.GetResultAsync(responseId); return result is null?NotFound():Ok(result);} }
